import React from "react";
import ParamCard from "./Tools/ParamCard";
import ParamHeader from "./Tools/ParamHeader";
import {THEME_COLORS} from "./Tools/Constants";

function Counter({
    value = 5,
    min = 0,
    max = 10,
    onChange,
    iconName = 'Heart',
    colorIndex = 6,
    onIconClick
}) {
    return (
        <ParamCard>
            <div className="flex items-center justify-between">
                <ParamHeader
                    label="爱心数量"
                    iconName={iconName}
                    colorIndex={colorIndex}
                    onIconClick={onIconClick}
                />
                <div className="flex items-center gap-2">
                    <button
                        onClick={() => onChange(Math.max(min, value - 1))}
                        className={`w-8 h-8 rounded-full bg-gradient-to-r ${THEME_COLORS[colorIndex].gradient} text-white font-bold hover:scale-110 transition-transform shadow-md`}
                    >
                        −
                    </button>
                    <span className={`text-lg font-bold ${THEME_COLORS[colorIndex].class} w-8 text-center`}>
                        {value}
                    </span>
                    <button
                        onClick={() => onChange(Math.min(max, value + 1))}
                        className={`w-8 h-8 rounded-full bg-gradient-to-r ${THEME_COLORS[colorIndex].gradient} text-white font-bold hover:scale-110 transition-transform shadow-md`}
                    >
                        +
                    </button>
                </div>
            </div>
        </ParamCard>
    );
}

export default Counter
